mcpAuth.serverConfigs.description:
Per-server authentication configuration keyed by the server name as it appears in mcp.servers / mcp.json. Only non-sensitive values are stored here. Sensitive credentials (client_secret, password, API keys) are always stored in SecretStorage and NEVER written to this file.

Example:
{
  "prod-api": {
    "method": "device",
    "clientId": "abc123",
    "deviceAuthEndpoint": "https://idp.example.com/oauth2/device_authz",
    "tokenEndpoint": "https://idp.example.com/oauth2/token",
    "scopes": "openid profile email"
  },
  "internal-service": {
    "method": "client_credentials",
    "clientId": "svc-account",
    "tokenEndpoint": "https://auth.internal/token"
  },
  "legacy-app": {
    "method": "password",
    "clientId": "legacy-client",
    "tokenEndpoint": "https://auth.legacy.com/token",
    "username": "svc-user"
  },
  "simple-service": {
    "method": "basic",
    "username": "admin"
  },
  "public-data": {
    "method": "api_key",
    "apiKeyHeader": "x-api-key"
  }
}
